import * as THREE from "https://esm.sh/three@0.160.0";
import { GLTFLoader } from "https://esm.sh/three@0.160.0/examples/jsm/loaders/GLTFLoader.js";

const FILE_MODEL_DATA_URL = "data:model/gltf-binary;base64,";
const MODEL_URL =
  window.location.protocol === "file:"
    ? FILE_MODEL_DATA_URL
    : new URL("./models/model-walk-run.glb", import.meta.url).href;
const MODEL_SCALE = 1.98;
const MODEL_Y_OFFSET = -1.46;
const MODEL_Y_ROTATION = 0;
const WALK_SPEED_THRESHOLD = 0.2;
const RUN_SPEED_THRESHOLD = 16;
const WALK_CYCLE_SPEED = 7.5;
const RUN_CYCLE_SPEED = 11.5;

const loader = new GLTFLoader();

function hideLegacyAvatar(playerRoot) {
  for (const child of playerRoot.children) {
    if (child.userData?.voxcelReplacement) continue;
    child.visible = false;
  }
}

function findClip(animations, pattern) {
  return animations.find((clip) => pattern.test(clip.name));
}

function createProceduralAnimator(model) {
  const bones = {};
  for (const name of [
    "Pelvis",
    "Spine_01",
    "Spine_02",
    "Chest",
    "Neck",
    "Head",
    "UpperArm_L",
    "LowerArm_L",
    "Hand_L",
    "UpperArm_R",
    "LowerArm_R",
    "Hand_R",
    "Thigh_L",
    "Calf_L",
    "Foot_L",
    "Thigh_R",
    "Calf_R",
    "Foot_R",
  ]) {
    bones[name] = model.getObjectByName(name) ?? null;
  }

  const base = {};
  for (const [name, bone] of Object.entries(bones)) {
    if (!bone) continue;
    base[name] = {
      rotation: bone.rotation.clone(),
      position: bone.position.clone(),
    };
  }

  let phase = 0;

  function setBoneRotation(name, x, y, z) {
    const bone = bones[name];
    const rest = base[name];
    if (!bone || !rest) return;
    bone.rotation.set(
      rest.rotation.x + x,
      rest.rotation.y + y,
      rest.rotation.z + z,
    );
  }

  function setBonePositionZ(name, z) {
    const bone = bones[name];
    const rest = base[name];
    if (!bone || !rest) return;
    bone.position.set(rest.position.x, rest.position.y + z, rest.position.z);
  }

  return {
    update(dt, speed) {
      const moving = speed > WALK_SPEED_THRESHOLD;
      if (!moving) {
        phase = 0;
        for (const [name, rest] of Object.entries(base)) {
          const bone = bones[name];
          if (!bone) continue;
          bone.rotation.copy(rest.rotation);
          bone.position.copy(rest.position);
        }
        return "idle";
      }

      const running = speed > RUN_SPEED_THRESHOLD;
      phase += dt * (running ? RUN_CYCLE_SPEED : WALK_CYCLE_SPEED);

      const legAmp = running ? 0.9 : 0.5;
      const armAmp = running ? 0.65 : 0.38;
      const bodyAmp = running ? 0.12 : 0.07;
      const bobAmp = running ? 0.06 : 0.035;

      const swing = Math.sin(phase);
      const counter = Math.sin(phase + Math.PI);
      const bob = Math.sin(phase * 2.0);

      setBoneRotation("Pelvis", bodyAmp * 0.35 * bob, 0, bodyAmp * 0.4 * swing);
      setBoneRotation("Spine_01", bodyAmp * 0.45 * bob, 0, bodyAmp * 0.12 * swing);
      setBoneRotation("Spine_02", bodyAmp * 0.65 * bob, 0, bodyAmp * 0.08 * swing);
      setBoneRotation("Chest", bodyAmp * bob, 0, bodyAmp * 0.06 * swing);
      setBoneRotation("Neck", bodyAmp * -0.18 * bob, 0, 0);
      setBoneRotation("Head", bodyAmp * -0.28 * bob, 0, 0);

      setBoneRotation("UpperArm_L", armAmp * counter, 0, armAmp * 0.12 * counter);
      setBoneRotation("LowerArm_L", -armAmp * 0.12 * Math.max(0, swing), 0, 0);
      setBoneRotation("Hand_L", 0, 0, armAmp * 0.05 * counter);

      setBoneRotation("UpperArm_R", armAmp * swing, 0, -armAmp * 0.12 * swing);
      setBoneRotation("LowerArm_R", -armAmp * 0.12 * Math.max(0, counter), 0, 0);
      setBoneRotation("Hand_R", 0, 0, -armAmp * 0.05 * swing);

      setBoneRotation("Thigh_L", legAmp * swing, 0, 0);
      setBoneRotation("Calf_L", Math.max(0, -legAmp * 0.7 * swing), 0, 0);
      setBoneRotation("Foot_L", Math.max(-0.2, legAmp * 0.25 * swing), 0, 0);

      setBoneRotation("Thigh_R", legAmp * counter, 0, 0);
      setBoneRotation("Calf_R", Math.max(0, -legAmp * 0.7 * counter), 0, 0);
      setBoneRotation("Foot_R", Math.max(-0.2, legAmp * 0.25 * counter), 0, 0);

      setBonePositionZ("Pelvis", bobAmp * (0.5 + 0.5 * bob));
      return running ? "run" : "walk";
    },
  };
}

function waitForPlayerRoot() {
  return new Promise((resolve, reject) => {
    const startedAt = performance.now();
    const timer = window.setInterval(() => {
      const handle = window.__voxcelPlayer;
      if (handle?.scene && handle?.playerRoot) {
        window.clearInterval(timer);
        resolve(handle);
        return;
      }
      if (performance.now() - startedAt > 15000) {
        window.clearInterval(timer);
        reject(new Error("Timed out waiting for player root"));
      }
    }, 50);
  });
}

async function mountReplacementAvatar() {
  const handle = await waitForPlayerRoot();
  if (handle.playerRoot.userData?.voxcelReplacementMounted) return;

  const gltf = await loader.loadAsync(MODEL_URL);
  const avatarRoot = new THREE.Group();
  avatarRoot.name = "ReplacementAvatar";
  avatarRoot.userData.voxcelReplacement = true;
  avatarRoot.scale.setScalar(MODEL_SCALE);
  avatarRoot.position.set(0, MODEL_Y_OFFSET, 0);
  avatarRoot.rotation.y = MODEL_Y_ROTATION;

  const model = gltf.scene;
  model.userData.voxcelReplacement = true;
  model.traverse((child) => {
    child.userData.voxcelReplacement = true;
    if (child.isMesh) {
      child.castShadow = true;
      child.receiveShadow = true;
      child.frustumCulled = false;
    }
  });
  avatarRoot.add(model);
  handle.playerRoot.add(avatarRoot);

  const animationRoot = model.getObjectByName("model_Rig") ?? model;
  const mixer = gltf.animations.length ? new THREE.AnimationMixer(animationRoot) : null;
  const walkClip = findClip(gltf.animations, /walk/i);
  const runClip = findClip(gltf.animations, /run/i);
  const walkAction = mixer && walkClip ? mixer.clipAction(walkClip, animationRoot) : null;
  const runAction = mixer && runClip ? mixer.clipAction(runClip, animationRoot) : null;
  const proceduralAnimator = createProceduralAnimator(model);
  const debugState = {
    hasMixer: !!mixer,
    animationRoot: animationRoot.name,
    walkClip: walkClip?.name ?? null,
    runClip: runClip?.name ?? null,
    walkTracks: walkClip?.tracks?.slice(0, 12).map((track) => track.name) ?? [],
    runTracks: runClip?.tracks?.slice(0, 12).map((track) => track.name) ?? [],
    proceduralMode: true,
    speed: 0,
    currentAction: null,
    dt: 0,
  };
  window.__voxcelAvatarDebug = debugState;

  if (walkAction) {
    walkAction.enabled = true;
    walkAction.play();
    walkAction.paused = true;
    walkAction.time = 0;
  }
  if (runAction) {
    runAction.enabled = true;
    runAction.play();
    runAction.paused = true;
    runAction.time = 0;
  }

  handle.playerRoot.userData.voxcelReplacementMounted = true;
  hideLegacyAvatar(handle.playerRoot);

  let lastTime = performance.now();
  let lastPosition = handle.playerRoot.getWorldPosition(new THREE.Vector3());
  let currentAction = null;

  function setCurrentAction(nextAction) {
    if (currentAction === nextAction) return;
    if (currentAction) {
      currentAction.stop();
      currentAction.enabled = true;
      currentAction.paused = true;
      currentAction.time = 0;
    }
    currentAction = nextAction;
    debugState.currentAction = currentAction?.getClip?.().name ?? null;
    if (currentAction) {
      currentAction.reset();
      currentAction.enabled = true;
      currentAction.paused = false;
      currentAction.play();
    }
  }

  function tick(now) {
    hideLegacyAvatar(handle.playerRoot);

    const dt = Math.max(0.001, (now - lastTime) / 1000);
    lastTime = now;

    const currentPosition = handle.playerRoot.getWorldPosition(new THREE.Vector3());
    const distance = currentPosition.distanceTo(lastPosition);
    const speed = distance / dt;
    debugState.speed = speed;
    debugState.dt = dt;
    lastPosition.copy(currentPosition);

    if (mixer) {
      if (speed > RUN_SPEED_THRESHOLD && runAction) {
        setCurrentAction(runAction);
      } else if (speed > WALK_SPEED_THRESHOLD && walkAction) {
        setCurrentAction(walkAction);
      } else {
        setCurrentAction(null);
      }
      mixer.update(dt);
    }

    debugState.currentAction = proceduralAnimator.update(dt, speed);

    requestAnimationFrame(tick);
  }

  requestAnimationFrame(tick);
}

mountReplacementAvatar().catch((error) => {
  console.error("Failed to mount replacement avatar", error);
});
